{
  "mode": "io",
  "tests": [
    {
      "name": "basic_onboarding_flow",
      "input": "{\"user_input\": \"I want to launch a new app challenge.\"}",
      "output": "{\"response\": \"Great! What is the main goal of your app?\"}",
      "notes": "Validates the initial AI response to a common challenge type."
    },
    {
      "name": "challenge_scope_clarification",
      "input": "{\"user_input\": \"I need help defining the problem statement.\"}",
      "output": "{\"response\": \"Can you describe the target audience for your challenge?\"}",
      "notes": "Checks if the AI can guide users in scoping their challenge effectively."
    },
    {
      "name": "duplicate_conversation_check",
      "input": "{\"previous_conversation\": true, \"user_input\": \"I already discussed this with the AI.\"}",
      "output": "{\"response\": \"Let's summarize what we discussed before proceeding.\"}",
      "notes": "Ensures the wizard avoids repeating previous conversations."
    },
    {
      "name": "input_validation_empty",
      "input": "{\"user_input\": \"\"}",
      "output": "{\"error\": \"Input cannot be empty.\"}",
      "notes": "Tests the system's handling of empty input."
    },
    {
      "name": "input_validation_special_characters",
      "input": "{\"user_input\": \"@#$%^&*()\"}",
      "output": "{\"error\": \"Invalid input. Please provide a valid challenge description.\"}",
      "notes": "Checks how the system responds to invalid characters."
    },
    {
      "name": "contextual_adaptation",
      "input": "{\"user_input\": \"I want to create a challenge for healthcare innovation.\"}",
      "output": "{\"response\": \"What specific healthcare issue are you addressing?\"}",
      "notes": "Validates the AI's ability to adapt recommendations based on context."
    },
    {
      "name": "multi-step_flow",
      "input": "{\"user_input\": \"Let's start the onboarding process.\"}",
      "output": "{\"response\": \"Step 1: Define your challenge. What is the main objective?\"}",
      "notes": "Tests the transition into the multi-step onboarding process."
    },
    {
      "name": "unexpected_input_handling",
      "input": "{\"user_input\": \"Tell me a joke.\"}",
      "output": "{\"error\": \"This wizard is for challenge onboarding only.\"}",
      "notes": "Ensures the system can handle off-topic inputs gracefully."
    }
  ],
  "assumptions": "The AI assistant is capable of understanding and processing user inputs in natural language.",
  "notes": "Focus on ensuring the onboarding experience is seamless and intuitive."
}
